interface my_if;
  logic sig_a, sig_b;
  modport mp1(input .a(sig_a), output .b(sig_b));
endinterface

interface my_if;
  logic sig_a, sig_b, sig_c, sig_d;
  modport mp1(input .a(sig_a), output .b(sig_b));
  modport mp2(input .a(sig_c), output .b(sig_d));
endinterface

module mod1(my_if.mp1 i);
  assign i.b = i.a;
endmodule

my_if myIf();
mod1 mod1Instance(myIf);
mod2 mod2Instance(myIf);
